from dataclasses import dataclass, field
from typing import Any
from jinja2 import Environment, BaseLoader, StrictUndefined, TemplateError
import re

@dataclass
class PromptTemplate:
    id: str
    version: str                      # semver: "1.2.3"
    body: str                         # Jinja2 template string
    required_vars: list[str]
    optional_vars: dict[str, Any] = field(default_factory=dict)
    model_hint: str = "claude-3-5-sonnet"
    temperature: float = 0.2

    def __post_init__(self):
        _env = Environment(loader=BaseLoader(), undefined=StrictUndefined)
        self._compiled = _env.from_string(self.body)

    def render(self, **kwargs: Any) -> str:
        missing = [v for v in self.required_vars if v not in kwargs]
        if missing:
            raise ValueError(f"[{self.id}@{self.version}] missing vars: {missing}")
        merged = {**self.optional_vars, **kwargs}
        try:
            return self._compiled.render(**merged)
        except TemplateError as exc:
            raise RuntimeError(f"[{self.id}@{self.version}] render error: {exc}") from exc


# Define a template
CLASSIFY_TEMPLATE = PromptTemplate(
    id="classify-intent",
    version="2.0.1",
    body="""You are an intent classifier. Output exactly one of: {{ labels | join(' | ') }}.

User message: {{ user_message }}

Intent:""",
    required_vars=["user_message", "labels"],
    temperature=0.0,
)

prompt = CLASSIFY_TEMPLATE.render(
    user_message="Can I get a refund?",
    labels=["billing", "support", "sales"],
)

from typing import Literal
import re

class TemplateRegistry:
    """In-process template registry with semantic-version routing."""

    def __init__(self):
        self._store: dict[str, dict[str, PromptTemplate]] = {}

    def register(self, template: PromptTemplate) -> None:
        bucket = self._store.setdefault(template.id, {})
        bucket[template.version] = template
        # Always keep 'latest' pointing to the highest semver
        latest = max(bucket, key=lambda v: tuple(int(x) for x in v.split(".")))
        bucket["latest"] = bucket[latest]

    def get(self, template_id: str, version: str = "latest") -> PromptTemplate:
        bucket = self._store.get(template_id)
        if not bucket:
            raise KeyError(f"Template not found: {template_id}")
        tmpl = bucket.get(version)
        if not tmpl:
            raise KeyError(f"Version {version} not found for {template_id}")
        return tmpl

    def ab_route(
        self,
        template_id: str,
        user_id: str,
        experiment: dict[str, float],  # {"2.0.1": 0.9, "2.1.0-beta": 0.1}
    ) -> PromptTemplate:
        import hashlib, random
        seed = int(hashlib.md5(f"{template_id}:{user_id}".encode()).hexdigest(), 16)
        rng = random.Random(seed)
        pick = rng.random()
        cumulative = 0.0
        for version, weight in experiment.items():
            cumulative += weight
            if pick < cumulative:
                return self.get(template_id, version)
        return self.get(template_id)  # fallback


registry = TemplateRegistry()
registry.register(CLASSIFY_TEMPLATE)
tmpl = registry.get("classify-intent", "2.0.1")
